import { Starlink } from './types';
export { Starlink } from './types';
/**
 * Provides a base-level abstraction for interacting with the Starlink Enterprise API
 */
export default abstract class BaseAPI {
    readonly client_id: string;
    protected readonly client_secret: string;
    /**
     * We are limited to 250 requests per minute from a single IP address
     * this cache helps to track this and automatically times out old
     * requests
     */
    private static readonly cache;
    private static readonly requestLimit;
    private static token?;
    readonly baseUrl = "https://web-api.starlink.com";
    constructor(client_id: string, client_secret: string);
    /**
     * Disconnects the internal rate-limit cache and releases its resources
     */
    static disconnect(): Promise<void>;
    /**
     * Attempts to authenticate with the Starlink Enterprise API
     * If it succeeds, the token is stored internally for later use
     *
     * @private
     */
    private authenticate;
    /**
     * Performs an HTTP request against the Starlink Enterprise API
     *
     * @param method
     * @param endpoint
     * @param params
     * @param payload
     * @param is_retry
     * @private
     */
    private execute;
    private static requestCount;
    /**
     * Performs an HTTP delete request against the Starlink Enterprise API
     *
     * @param endpoint
     * @param params
     * @protected
     */
    protected delete<Type extends Starlink.Response = any>(endpoint: string, params?: Record<string, any>): Promise<Type>;
    /**
     * Performs an HTTP get request against the Starlink Enterprise API
     *
     * @param endpoint
     * @param params
     * @protected
     */
    protected get<Type extends Starlink.Response = any>(endpoint: string, params?: Record<string, any>): Promise<Type>;
    /**
     * Performs an HTTP post request against the Starlink Enterprise API
     *
     * @param endpoint
     * @param payload
     * @protected
     */
    protected post<Type extends Starlink.Response = any>(endpoint: string, payload?: object): Promise<Type>;
    /**
     * Performs an HTTP put request against the Starlink Enterprise API
     *
     * @param endpoint
     * @param payload
     * @protected
     */
    protected put<Type extends Starlink.Response = any>(endpoint: string, payload?: object | string): Promise<Type>;
}
